var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，他是必不可少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼とともにいることを。","ENG":"that you'll be with him, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和他一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called him to your office. He said he'd be here soon.","TWN":"做好心理準備後，你將他傳喚到老闆辦公室，他說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그렇군요. 종신 계약입니까. 제게도 이런 날이 오는군요.","JPN":"なるほど。終身契約ですか。俺にもこんな日が来るんですね。","ENG":"I see. A lifetime contract, huh? Finally, this day has come.","TWN":"原來如此。終身契約嗎？沒想到我也會有這一天。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"침식체 사냥을 돈벌이로 여기는 용병들의 우두머리께서, 먼저 손을 내미신다......","JPN":"侵食体狩りを金儲けの手段としている傭兵達のボスともあろう方が、先に手を差し伸べてくださると……","ENG":"The leader of mercenaries making big bucks on C.O. hunting reached out to me first?","TWN":"靠狩獵侵蝕體賺錢的傭兵頭目，居然先向我伸出了友誼之手……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이거 원, 제가 어떻게 받아들일 거라고 생각하셨습니까?","JPN":"参りましたね。俺がどう反応するか、予想がつかないわけじゃないでしょうに。","ENG":"Man, how do you expect me to respond?","TWN":"我的天，你是要我怎麼接受啦？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......뭐, 그러려니 해야죠.","JPN":"……まあ、ここは穏便に行くべきでしょうね。","ENG":"... Well, okay.","TWN":"……算了，真沒辦法。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"앞뒤 안 가려도 공사는 구분할 줄 압니다. 다른 인간이 이런 소리를 했다면 박살을 내 줬겠지만......","JPN":"こう見えても公私は弁えてるつもりです。他の奴がそんなことを抜かしたら、後先考えずボコボコにしてるところですが……","ENG":"I may be reckless sometimes, but I'm not completely irrational. If someone else made me the offer, I would have bashed their head in, of course.","TWN":"雖然我這人做事不動大腦，但卻公私分明。如果是其他人對我說這種話，我會狠狠地修理他，但是……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"사장님께선 다른 이유 때문에 여기 눌러앉으신 것 아닙니까?","JPN":"社長がここにいるのには、何か他に理由があるのでしょう？","ENG":"But you've got a different reason to stay with this company, don't you?","TWN":"老闆，是有其他理由，才會坐在這裡的吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"하하, 머리 쓰는 건 귀찮아해도 감은 살아 있습니다. 회사 돌아가는 모양을 보면 수상한 냄새가 풀풀 풍기거든요.","JPN":"ハハ、頭を使うのは苦手ですが、勘は冴えてますから。この会社の様子を見てると、怪しい匂いがプンプンするんですよ。","ENG":"Hah hah. I don't like using my brain, but I'm pretty intuitive. There's something definitely hinky about the way you run this company.","TWN":"哈哈，雖然我覺得動腦很麻煩，但我可是有第六感的！一看公司的營運情況，我就聞到一股可疑的味道。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"아니라고 해도 지금은 그런 셈 치시죠. 사장님이 꽤 마음에 들어서 말입니다.","JPN":"違うと言うのなら、とりあえず今はそういうことにしておきましょう。社長のことは気に入っていますので。","ENG":"If you don't want to admit it, then I'll let it slide for now. Because I'm rather fond of you.","TWN":"您說不是，那就當做不是吧。我還是挺中意老闆您的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"제 불 같은 성질머리 좀 죽이라고 하실 거면, 그럴싸한 핑곗거리도 하나 던져주셔야죠. 안 그렇습니까?","JPN":"この燃え滾る魂を鎮めてほしいなら、何かそれらしい理由でも提示してもらわないと話になりません。そこんところ、よろしくお願いしますよ。","ENG":"If you want me to keep my temper in check, then you'd better give me a reason to. Am I wrong?","TWN":"如果你想要我改改我火暴的脾氣，至少該給我合理的理由吧，不是嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};